-- Fix + seed demo services — Part 2 of 2. ক্রমানুসারে চালান (Supabase SQL Editor)।
-- সার্ভিস তালিকা 500 হওয়ার বাগ ঠিক করে (benefits/requirements shape)। idempotent।
BEGIN;
-- fix already-inserted services (old broken benefits/requirements shape → valid list[str])
UPDATE services SET process_steps='[{"step": 1, "title": "Requirement", "description": "Share your requirement and we assess the scope."}, {"step": 2, "title": "Quotation", "description": "Transparent quote and timeline before we begin."}, {"step": 3, "title": "Delivery", "description": "We deliver, review and provide after-sales support."}]'::jsonb, benefits='["Experienced local team", "Transparent, fair pricing", "Fast turnaround & dedicated support"]'::jsonb, requirements='["Basic project details or a clear brief", "Contact number for coordination"]'::jsonb, faq='[{"question": "How long does this service take?", "answer": "Timeline depends on scope; we confirm it with your quotation."}, {"question": "Can I replace this demo service later?", "answer": "Yes — every service here is fully editable from the admin panel."}]'::jsonb WHERE tags::jsonb @> '["demo-seed"]'::jsonb;
COMMIT;
